// Extract and validate incoming webhook payload.
// Expected fields:
//   action: 'import'
//   import_id: string (UUID) — shop_marketplace_imports row
//   connection_id: string (UUID) — shop_marketplace_connections row
//   listing_ids: string[] — external listing IDs to import
//   tenant_id: string (UUID)

const body = $('Webhook').first().json.body;

if (!body.import_id || !body.connection_id || !body.listing_ids || !body.tenant_id) {
  throw new Error(`Missing required fields: import_id=${body.import_id}, connection_id=${body.connection_id}, listing_ids=${JSON.stringify(body.listing_ids)}, tenant_id=${body.tenant_id}`);
}

if (!Array.isArray(body.listing_ids)) {
  throw new Error(`listing_ids must be an array, got: ${typeof body.listing_ids}`);
}

return {
  import_id: body.import_id,
  connection_id: body.connection_id,
  listing_ids: body.listing_ids,
  tenant_id: body.tenant_id,
};

// Fetch decrypted connection credentials from Supabase.
// Retrieves access_token + marketplace type for API calls.

const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Extract Payload').first().json;
const SUPABASE_URL = 'https://zsrpdslhnuwmzewwoexr.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabaseGet(table, filterKey, filterValue, select) {
  const params = new URLSearchParams();
  params.append(filterKey, `eq.${filterValue}`);
  if (select) params.append('select', select);
  params.append('limit', '1');

  const url = `${SUPABASE_URL}/rest/v1/${table}?${params.toString()}`;

  return new Promise((resolve, reject) => {
    const req = https.request(url, {
      method: 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
      }
    }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch (e) { reject(new Error(`Parse error: ${body}`)); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

try {
  const connections = await supabaseGet(
    'shop_marketplace_connections_decrypted',
    'id', input.connection_id,
    'id,marketplace,access_token,refresh_token,token_expires_at,account_id'
  );
  if (!connections.length) throw new Error(`Connection not found: ${input.connection_id}`);
  const connection = connections[0];

  // Mark import as running
  await new Promise((resolve, reject) => {
    const body = JSON.stringify({ status: 'running', started_at: new Date().toISOString() });
    const url = `${SUPABASE_URL}/rest/v1/shop_marketplace_imports?id=eq.${input.import_id}`;
    const req = https.request(url, {
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal',
      }
    }, (res) => {
      res.on('data', () => {});
      res.on('end', resolve);
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });

  return {
    import_id: input.import_id,
    connection_id: input.connection_id,
    listing_ids: input.listing_ids,
    tenant_id: input.tenant_id,
    marketplace: connection.marketplace,
    access_token: connection.access_token,
    refresh_token: connection.refresh_token || null,
    token_expires_at: connection.token_expires_at || null,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Batch import listings from marketplace.
// For each listing_id in listing_ids:
//   1. Call marketplace getMyListings equivalent (fetch listing details)
//   2. Duplicate check via shop_marketplace_listings (connection_id + external_listing_id)
//   3. If duplicate: skipped_items++
//   4. If new: create shop_products + shop_marketplace_listings record
//   5. Progress callback every 10 items
//
// Rate limiting: 100ms delay between API calls

const Sentry = require('@sentry/node');
const https = require('https');

const input = $('Fetch Credentials + Mark Running').first().json;
const { import_id, connection_id, listing_ids, tenant_id, marketplace, access_token } = input;

const SUPABASE_URL = 'https://zsrpdslhnuwmzewwoexr.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const HOST_URL = $env.HOST_URL;
const SECRET = $env.WORKFLOW_TRIGGER_SECRET;

function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function supabaseRequest(method, path, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  const bodyStr = body ? JSON.stringify(body) : null;

  return new Promise((resolve, reject) => {
    const options = {
      method,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };

    const req = https.request(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, body: data ? JSON.parse(data) : null });
        } catch (e) {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

async function marketplaceGetListing(externalListingId) {
  const baseUrl = marketplace === 'olx'
    ? 'https://www.olx.pl/api/partner'
    : 'https://api.allegro.pl';

  const path = marketplace === 'olx'
    ? `/offers/${externalListingId}`
    : `/sale/offers/${externalListingId}`;

  const headers = marketplace === 'olx'
    ? { 'Authorization': `Bearer ${access_token}`, 'Version': '2.0' }
    : {
        'Authorization': `Bearer ${access_token}`,
        'Accept': 'application/vnd.allegro.public.v1+json',
        'Content-Type': 'application/vnd.allegro.public.v1+json',
      };

  return new Promise((resolve, reject) => {
    const req = https.request(`${baseUrl}${path}`, { method: 'GET', headers }, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, body: data ? JSON.parse(data) : null });
        } catch (e) {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

function extractListingData(listingBody, externalListingId) {
  // Normalise OLX and Allegro response shapes into a common structure
  if (marketplace === 'olx') {
    const offer = listingBody?.data || listingBody || {};
    return {
      title: offer.title || `OLX listing ${externalListingId}`,
      description: offer.description?.networking === false ? '' : (offer.description || ''),
      price: offer.price?.value ? offer.price.value / 100 : 0,
      currency: offer.price?.currency || 'PLN',
      external_url: offer.url || null,
    };
  }
  // Allegro
  const offer = listingBody || {};
  const priceAmount = offer.sellingMode?.price?.amount;
  return {
    title: offer.name || `Allegro listing ${externalListingId}`,
    description: offer.description?.sections?.[0]?.items?.[0]?.content || '',
    price: priceAmount ? parseFloat(priceAmount) : 0,
    currency: offer.sellingMode?.price?.currency || 'PLN',
    external_url: externalListingId ? `https://allegro.pl/oferta/${externalListingId}` : null,
  };
}

async function sendProgressCallback(importedItems, skippedItems) {
  const payload = JSON.stringify({
    import_id,
    event: 'progress',
    imported_items: importedItems,
    skipped_items: skippedItems,
  });

  return new Promise((resolve) => {
    const req = https.request(`${HOST_URL}/api/marketplace/import`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SECRET}`,
        'Content-Type': 'application/json',
      },
    }, (res) => {
      res.on('data', () => {});
      res.on('end', resolve);
    });
    req.on('error', resolve); // never reject — fire-and-forget
    req.write(payload);
    req.end();
  });
}

try {
  let importedItems = 0;
  let skippedItems = 0;
  const errorLog = [];

  for (let i = 0; i < listing_ids.length; i++) {
    const externalListingId = listing_ids[i];

    try {
      // Duplicate check: does this external_listing_id already exist for this connection?
      const existingResult = await supabaseRequest(
        'GET',
        `shop_marketplace_listings?connection_id=eq.${connection_id}&external_listing_id=eq.${externalListingId}&select=id&limit=1`,
        null
      );

      if (existingResult.body && Array.isArray(existingResult.body) && existingResult.body.length > 0) {
        // Already imported — skip
        skippedItems++;
      } else {
        // Fetch listing details from marketplace API
        await delay(100); // rate limiting
        const listingResult = await marketplaceGetListing(externalListingId);

        if (listingResult.status >= 400) {
          errorLog.push({ listingId: externalListingId, message: `API error: HTTP ${listingResult.status}` });
          skippedItems++;
        } else {
          const listingData = extractListingData(listingResult.body, externalListingId);

          // Create shop_products record
          const productResult = await supabaseRequest('POST', 'shop_products', {
            tenant_id,
            title: listingData.title,
            short_description: listingData.description,
            price: listingData.price,
            currency: listingData.currency,
            listing_type: 'direct',
            is_published: false,
          });

          if (productResult.status >= 400 || !productResult.body?.[0]?.id) {
            errorLog.push({ listingId: externalListingId, message: 'Failed to create product' });
            skippedItems++;
          } else {
            const productId = productResult.body[0].id;

            // Create shop_marketplace_listings record linking product to marketplace
            await supabaseRequest('POST', 'shop_marketplace_listings', {
              tenant_id,
              product_id: productId,
              connection_id,
              marketplace,
              external_listing_id: externalListingId,
              external_url: listingData.external_url,
              status: 'active',
              last_sync_status: 'ok',
              last_synced_at: new Date().toISOString(),
              published_at: new Date().toISOString(),
            });

            importedItems++;
          }
        }
      }
    } catch (itemErr) {
      Sentry.captureException(itemErr);
      errorLog.push({ listingId: externalListingId, message: itemErr.message || 'Unknown error' });
      skippedItems++;
    }

    // Progress callback every 10 items
    if ((i + 1) % 10 === 0) {
      await sendProgressCallback(importedItems, skippedItems);
    }
  }

  return {
    import_id,
    imported_items: importedItems,
    skipped_items: skippedItems,
    error_log: errorLog,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Prepare completed callback payload
const result = $('Process Listings').first().json;

return {
  import_id: result.import_id,
  event: 'completed',
  imported_items: result.imported_items,
  skipped_items: result.skipped_items,
  error_log: result.error_log,
};

// Error handler — called when Fetch Credentials or Process Listings throws.
// Sends failure callback to CMS.

const Sentry = require('@sentry/node');

const input = $('Extract Payload').first().json;

let errorMessage;
try {
  const errorItem = $input.first().json;
  errorMessage =
    errorItem?.error?.message ||
    errorItem?.message ||
    errorItem?.error ||
    'Unknown error in Marketplace Import workflow';
} catch {
  errorMessage = 'Unknown error in Marketplace Import workflow';
}

Sentry.captureException(new Error(`[Marketplace Import] Failed: ${errorMessage}`));
await Sentry.flush(2000);

return {
  import_id: input.import_id,
  event: 'error',
  error_log: [{ message: errorMessage }],
};
